import java.util.*;

class MKAverage {

    private int m;
    private int k;
    private Deque<Integer> window;
    private long sum;

    public MKAverage(int m, int k) {
        this.m = m;
        this.k = k;
        this.window = new LinkedList<>();
        this.sum = 0;
    }

    public void addElement(int num) {
        window.addLast(num);
        sum += num;
        if (window.size() > m) {
            sum -= window.removeFirst();
        }
    }

    public int calculateMKAverage() {
        if (window.size() < m) {
            return -1;
        }
        List<Integer> temp = new ArrayList<>(window);
        Collections.sort(temp);
        int start = temp.size() - m;
        int end = start + m;
        long avgSum = 0;
        for (int i = start + k; i < end - k; i++) {
            avgSum += temp.get(i);
        }
        return (int) (avgSum / (m - 2 * k));
    }
}
